elif isCorp:
    op1 = app.op['get_corporations_corporation_id_assets'](corporation_id=g.corpID)

r = esi.request(op1)
if 'X-Pages' in r.header and r.header['X-Pages'][0]>1:
    for page in range(2, r.header['X-Pages'][0]):
        if isCharacter:
            opn = app.op['get_characters_character_id_assets'](character_id=g.characterID, page=page)
        elif isCorp:
            opn = app.op['get_corporations_corporation_id_assets'](corporation_id=g.corpID, page=page)
        ops.append(opn)
    # perform multiple requests for pages 2, 3 etc
```

while it could be much easier to do if I could reuse previously defined `op` with just adding `page` to it.

